window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["j"]={"Jan": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Jakub": "Imię to było znane w <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamii</a> w brzmieniu Ja-ah-qu-ub-el i w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a> Ja’qob-hr. Popularne imię biblijne – nosił je syn <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>, a także dwóch Apostołów. W Polsce imię Jakub znane jest od XIII wieku, w formach i ze zdrobnieniami: Jakuś, Jakób, Jakob, Jakow, Jekub, Jokob, Jokub, Jakusz, Jakuszek, Jakubek, Jakubko, Jaksa, Kiba, Kuba, Kusz, Kuszęt, Kubuś.", "Józef": "<b>Józef</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יוסף&#8206; yōsēp̄) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">patriarchy Józefa</a>, syna <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i Racheli; oznacza ono „niech przyda <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”. Jest to skrócona forma imienia Josifiasz: „(by) <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jah</a> dodał (pomnożył)”. W zdrobnieniach występuje w formach: Józek, Józefek, Józuś, Ziutek, Józio.", "Jerzy": "<b>Jerzy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, polski odpowiednik greckiego <i>Georgios</i>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;γεωργός (<i>geōrgos</i>), „pracownik ziemny”, „rolnik”, które stało się imieniem w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języku greckim</a>: <i>Γεώργιος</i> (Geōrgios) i <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Georgius</em>. Słowo <i>γεωργός</i> powstało w wyniku połączenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;γῆ (Ge), „ziemia”, „gleba” i ἔργον (ergon), „praca”.", "Jacek": "<b>Jacek</b>, <b>Jacenty</b> – imię męskie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> pochodzenia (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ὑάκινθος <i>Hyakinthos</i>, <a href=\"https://pl.wikipedia.org/wiki/Hiacynt_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">hiacynt</a>), od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowanej</a> formy <a href=\"https://pl.wikipedia.org/wiki/Hiacynt_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">imienia Hiacynt</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Hyacinthus</i>).", "Janusz": "<b>Janusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone na gruncie języka polskiego od imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a>; pierwotnie była to forma zdrobniała, ale od bardzo dawna występuje jako samodzielne imię, być może nawet od XII wieku (najstarsze zapisy pochodzą z lat 1145 i 1178). Regionalnie do dziś tworzy się od imienia <i>Jan</i> zdrobnienie <i>Janusz</i>.", "Jarosław": "<b>Jarosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię słowiańskie</a> oznaczające kogoś, kto ma <i>mocną, silną sławę</i>. Słowo <i>jary</i> = <i>krzepki, mocny, silny</i> w okresie przedchrześcijańskim miało to samo znaczenie co słowo <i>święty</i>. Słowo <i>święty</i> dopiero później przyjęło swoje obecne znaczenie. Zatem w okresie przed <a href=\"https://pl.wikipedia.org/wiki/Chrzest_Polski\" target=\"_blank\" rel=\"noopener noreferrer\">chrztem Polski</a> imiona <i>Jarosław</i> i <i>Świętosław</i> znaczyły to samo. Później, w okresie <a href=\"https://pl.wikipedia.org/wiki/Chrystianizacja\" target=\"_blank\" rel=\"noopener noreferrer\">chrystianizacji</a>, imiona <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskie</a> zastępowano <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskimi</a>.", "Julian": "<b>Julian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia łacińskiego. Powstało w wyniku spolonizowania łacińskiego imienia <i>Julianus</i>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> występuje od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>.", "Joachim": "<b>Joachim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, znaczy „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> pocieszy, pokrzepi, wywyższy”. Poświadczone w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a> w formach <i>Jachym</i>, <i>Jochym</i>, <i>Joachym</i>, <i>Achym</i>.", "Juliusz": "<b>Juliusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające należącego do rodu Juliuszów (<i>Iulii</i>). Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Julia\" target=\"_blank\" rel=\"noopener noreferrer\">Julia</a>.", "Jędrzej": "<b>Jędrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wariant imienia <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>, którego pierwsze poświadczenie pochodzi z 1390 roku. Świadomość pochodzenia Jędrzeja od Andrzeja utrzymała się i Jędrek, zwłaszcza w niektórych regionach, funkcjonuje jako spieszczenie imienia Andrzej.", "Jeremi": "<b>Jeremi</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jeremiasz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jeremiasz</a>.", "Jonasz": "<b>Jonasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יוֹנָה&#8206; <i>Jona</i>, dosł. „gołąb”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωνᾶς) – <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">izraelski</a>, żyjący i działający w VIII wieku p.n.e., w Izraelu i Asyrii, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Gat-Chefer\" target=\"_blank\" rel=\"noopener noreferrer\">Gat-Chefer</a>. Opisany w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnej</a> <i><a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Jonasza\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Jonasza</a></i>, której autorstwo jemu się właśnie przypisuje.", "Jonatan": "<b>Jonatan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiej frazy <i>Yehonatan</i> oznaczającej „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> dał”.", "Jacenty": "<b>Jacek</b>, <b>Jacenty</b> – imię męskie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> pochodzenia (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ὑάκινθος <i>Hyakinthos</i>, <a href=\"https://pl.wikipedia.org/wiki/Hiacynt_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">hiacynt</a>), od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowanej</a> formy <a href=\"https://pl.wikipedia.org/wiki/Hiacynt_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">imienia Hiacynt</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Hyacinthus</i>).", "Jaromir": "<b>Jaromir</b>, <b>Jaromiar</b>, <b>Jeromiar</b>, <b>Jeromier</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Składa się z członów <i>Jaro</i> („surowy, ostry”) i <i>mir</i> („pokój”).", "Jordan": "<b>Jordan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Jordan_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">Jordan</a>, w której chrzcił święty <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a>. Imię stało się popularne w Europie od czasów <a href=\"https://pl.wikipedia.org/wiki/Wyprawy_krzy%C5%BCowe\" target=\"_blank\" rel=\"noopener noreferrer\">wypraw krzyżowych</a>, kiedy to chrzczono dzieci w wodzie z Jordanu, na pamiątkę nadając także to imię. Po hebrajsku <i>hay-Yarden</i> oznacza „płynący w dół”, „obniżający się”.", "Joshua": "<b>Jozue</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> יהושׁע – „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest wybawieniem”) – imię noszone przez tytułową postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnej</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Jozuego\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Jozuego</a>.", "Johannes": "Oprócz poparcia wysokich urzędników Jan zyskał sobie przychylność części senatorów, w tym wpływowej rodziny Anicjuszy. Po jego stronie opowiedział się dowódca <a href=\"https://pl.wikipedia.org/wiki/Flawiusz_Kastynus\" target=\"_blank\" rel=\"noopener noreferrer\">Kastynus</a> wyznaczony na konsula w 424. Poparcia nowemu władcy nie udzielił Bonifacjusz, który był komesem Afryki, co miało duże znaczenie dla dostaw zboża do Italii i spowodowało odsunięcie się senatorów od Jana. Skłoniło to Jana do wysłania w 424 wojsk do Afryki w celu podporządkowania sobie Bonifacjusza i zapewnienia ciągłości dostaw zaopatrzenia. Wyprawa zakończyła się niepowodzeniem. Tymczasem w Galii doszło do walk między zwolennikami i przeciwnikami Jana.", "Justin": "<b>Justyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od „iustus” – sprawiedliwy.", "Justyn": "<b>Justyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od „iustus” – sprawiedliwy.", "January": "<b>January</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Janus\" target=\"_blank\" rel=\"noopener noreferrer\">Janusa</a>, jednak pierwotnie oznaczało chłopca, który urodził się w styczniu (po łacinie <i>mensis Ianuarius</i>).", "Johann": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Jurand": "<b>Jurand</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Jego forma jest wynikiem pomyłki – błędnego odczytania w XIX wieku przez historyka <a href=\"https://pl.wikipedia.org/wiki/Franciszek_Piekosi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszka Piekosińskiego</a> średniowiecznych zapisów znanego w Polsce imienia <i><b>Jarand</b></i>, które jest formą imienia <a href=\"https://pl.wikipedia.org/wiki/Arnold_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Arnold</a>. Imię Jurand rozpropagował <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a> powieścią <i><a href=\"https://pl.wikipedia.org/wiki/Krzy%C5%BCacy_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Krzyżacy</a></i>.", "Jarema": "<b>Jarema</b> – (<b>&#8207;יִרְמְיָהוּ&#8206;</b> <b>Yirməyāhū</b>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słów <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> <i>Jirme-jahu</i> oznaczających „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, podnieś z upadku”.", "Johan": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Joni": "<b>Joni</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> योनि, <a href=\"https://pl.wikipedia.org/wiki/Trl.\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> <i>yoni</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> yoni, „łono”, „źródło”) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjskie</a> określenie <a href=\"https://pl.wikipedia.org/wiki/%C5%BBe%C5%84ski_uk%C5%82ad_p%C5%82ciowy\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskich organów płciowych</a> zarówno w znaczeniu fizycznym (np. w <a href=\"https://pl.wikipedia.org/wiki/Kama_Sutra\" target=\"_blank\" rel=\"noopener noreferrer\">Kamasutrze</a>), jak i w znaczeniu religijno-duchowym, jako symbol <a href=\"https://pl.wikipedia.org/wiki/Bogini\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>, źródła życia i całego wszechświata. Termin ten poza tym używany jest w najrozmaitszych znaczeniach przenośnych np. „łono”, „źródło”, „naczynie”, „początek”.", "Jun": "<b>Jun</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;じゅん, ジュン) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety, jak i przez mężczyzn.", "Jesse": "Jesse pochodził z pokolenia <a href=\"https://pl.wikipedia.org/wiki/Juda_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Judy</a>. Po mieczu był wnukiem <a href=\"https://pl.wikipedia.org/wiki/Booz\" target=\"_blank\" rel=\"noopener noreferrer\">Booza</a> i <a href=\"https://pl.wikipedia.org/wiki/Rut\" target=\"_blank\" rel=\"noopener noreferrer\">Rut</a>. Według 1 Krn 2,13-16 miał siedmiu synów – Eliaba, Abinadaba, Szimeę, Netaneela, Raddaja, Osema i Dawida – a także dwie córki, Seruję i Abigail, natomiast według 1 Sm 16,10n i 1 Sm 17,12 – ośmiu synów.", "Janisław": "<b>Janisław</b> – imię męskie, będące neologizmem utworzonym poprzez dodanie do <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> typowej dla imion słowiańskich końcówki <i>-sław</i>.", "Johnny": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Jarogniew": "<b>Jarogniew</b>, <b>Jerogniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Jaro-</i> („świeży, gorący”, ale też „gniewny, srogi, surowy”) i <i>-gniew</i> („gniew”). Mogło oznaczać „ten, którego gniew jest srogi”. Patronem tego imienia w Kościele katolickim jest bł. Jarogniew Wojciechowski, którego wspomnienie obchodzi się 12 czerwca.", "Józefat": "<b>Jozafat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>, hebr. <b>יהושפט</b> (Jehoszafat), oznaczające \"Bóg osądził\"; jego synonimem jest imię <a href=\"https://pl.wikipedia.org/wiki/Abidan\" target=\"_blank\" rel=\"noopener noreferrer\">Abidan</a>. W Polsce była w użyciu również forma <i><b>Józefat</b></i> lub <b>Józafat</b>, powstała przez pomieszanie Jozafata z <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Józefem</a>. Do pewnej popularności tego imienia w Polsce przyczynił się św. <a href=\"https://pl.wikipedia.org/wiki/Jozafat_Kuncewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Jozafat Kuncewicz</a>, żyjący w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>, męczennik, unicki <a href=\"https://pl.wikipedia.org/wiki/Archieparchia_po%C5%82ocka_(unicka)\" target=\"_blank\" rel=\"noopener noreferrer\">arcybiskup połocki</a>.", "Januariusz": "<b>Januariusz</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oboczna forma imienia <a href=\"https://pl.wikipedia.org/wiki/January\" target=\"_blank\" rel=\"noopener noreferrer\">January</a>.", "Jian": "<b>Jian</b> (<a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 剑&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. trad.</a> 劍&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>jiàn</i>) to długi, jednoręczny, obosieczny <a href=\"https://pl.wikipedia.org/wiki/Miecz\" target=\"_blank\" rel=\"noopener noreferrer\">miecz</a> <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> używany od przeszło 2500 lat. Najstarsze źródła opisujące miecz pochodzą z <a href=\"https://pl.wikipedia.org/wiki/VII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VII w. p.n.e.</a> z <a href=\"https://pl.wikipedia.org/wiki/Okres_Wiosen_i_Jesieni\" target=\"_blank\" rel=\"noopener noreferrer\">Okresu Wiosen i Jesieni</a> (tzw. <a href=\"https://pl.wikipedia.org/wiki/Miecz_Goujiana\" target=\"_blank\" rel=\"noopener noreferrer\">miecz Goujiana</a>, władcy królestwa <a href=\"https://pl.wikipedia.org/wiki/Yue_(okres_Zhou)\" target=\"_blank\" rel=\"noopener noreferrer\">Yue</a>). Historyczne miecze miały od 45 do 80 cm długości. Obecne modele mają około 70 cm, a ich waga to ok. 700-900 gramów. Dla lepszego wyważenia do <a href=\"https://pl.wikipedia.org/wiki/G%C5%82owica_(bro%C5%84_bia%C5%82a)\" target=\"_blank\" rel=\"noopener noreferrer\">głowicy</a> doczepiano podwójny pompon.", "Jared": "<b>Jared</b> – imię męskie pochodzenia biblijnego, po polsku <a href=\"https://pl.wikipedia.org/wiki/Jered\" target=\"_blank\" rel=\"noopener noreferrer\">Jered</a>.", "Johnson": "<b>Johnson</b> – angielskie i szkockie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko_patronimiczne\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko patronimiczne</a> pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka staroangielskiego</a> oznaczające „syn <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Johna</a>”. Na przestrzeni wieków nazwisko wielokrotnie zmieniało zapis przybierając formę <i>Jonessone</i>, <i>Jonesone</i>, <i>Johnson</i>, <i>Johanson</i>, <i>Jonson</i>, <i>Geynson</i> czy <i>Jeynson</i>. W 1990 w <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> nosiło je 2&#160;232&#160;100 osób.", "Janus": "Od niego pochodzi <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińska</a> nazwa miesiąca <a href=\"https://pl.wikipedia.org/wiki/Stycze%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">stycznia</a> (<i>Ianuarius</i>). W późniejszych przedstawieniach <a href=\"https://pl.wikipedia.org/wiki/Alegoria\" target=\"_blank\" rel=\"noopener noreferrer\">alegorycznych</a> (<a href=\"https://pl.wikipedia.org/wiki/Renesans\" target=\"_blank\" rel=\"noopener noreferrer\">renesans</a>, <a href=\"https://pl.wikipedia.org/wiki/Barok\" target=\"_blank\" rel=\"noopener noreferrer\">barok</a>) <a href=\"https://pl.wikipedia.org/wiki/Personifikacja\" target=\"_blank\" rel=\"noopener noreferrer\">uosabiał zimę</a>.", "Jim": "Imię to było znane w <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamii</a> w brzmieniu Ja-ah-qu-ub-el i w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a> Ja’qob-hr. Popularne imię biblijne – nosił je syn <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>, a także dwóch Apostołów. W Polsce imię Jakub znane jest od XIII wieku, w formach i ze zdrobnieniami: Jakuś, Jakób, Jakob, Jakow, Jekub, Jokob, Jokub, Jakusz, Jakuszek, Jakubek, Jakubko, Jaksa, Kiba, Kuba, Kusz, Kuszęt, Kubuś.", "Jozue": "Jozue był synem Nuna (Nona) z plemienia Efraima. Urodził się w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a> podczas niewoli egipskiej. Jego pierwotne imię to <a href=\"https://pl.wikipedia.org/wiki/Ozeasz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ozeasz (Hoszea) hbr. הוֹשֵׁעַ - „Jahwe wybawił\"</a>, <a href=\"https://pl.wikipedia.org/wiki/Jozue_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">imię Jozue</a> nadane mu zostało przez Mojżesza. Po śmierci <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesza</a> został przywódcą <a href=\"https://pl.wikipedia.org/wiki/%C5%BBydzi\" target=\"_blank\" rel=\"noopener noreferrer\">Izraelitów</a>, wprowadził ich do ziemi <a href=\"https://pl.wikipedia.org/wiki/Kanaan\" target=\"_blank\" rel=\"noopener noreferrer\">Kanaan</a> i podbił ją. Żył 110 lat. Po jego śmierci rozpoczął się trudny czas dla ludu Izraela.", "Jakób": "Imię to było znane w <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamii</a> w brzmieniu Ja-ah-qu-ub-el i w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a> Ja’qob-hr. Popularne imię biblijne – nosił je syn <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>, a także dwóch Apostołów. W Polsce imię Jakub znane jest od XIII wieku, w formach i ze zdrobnieniami: Jakuś, Jakób, Jakob, Jakow, Jekub, Jokob, Jokub, Jakusz, Jakuszek, Jakubek, Jakubko, Jaksa, Kiba, Kuba, Kusz, Kuszęt, Kubuś.", "Juda": "<b>Juda</b>, <b>Judasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Wywodzi się od słowa יהדה <i>jehudah</i> oznaczającego <i>chwała Jahwe</i>.", "Johny": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Janko": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Jaksa": "Imię to było znane w <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamii</a> w brzmieniu Ja-ah-qu-ub-el i w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a> Ja’qob-hr. Popularne imię biblijne – nosił je syn <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>, a także dwóch Apostołów. W Polsce imię Jakub znane jest od XIII wieku, w formach i ze zdrobnieniami: Jakuś, Jakób, Jakob, Jakow, Jekub, Jokob, Jokub, Jakusz, Jakuszek, Jakubek, Jakubko, Jaksa, Kiba, Kuba, Kusz, Kuszęt, Kubuś.", "Jojo": "<b>Jojo</b> (inaczej zwane kołem Maxwella) – rodzaj <a href=\"https://pl.wikipedia.org/wiki/Zabawka\" target=\"_blank\" rel=\"noopener noreferrer\">zabawki</a> w postaci ciężarka-szpulki zawieszonego na sznurku. Ciężarek, opuszczony na sznurku trzymanym za nieumocowany koniec, rozwija go wpadając w <a href=\"https://pl.wikipedia.org/wiki/Ruch_obrotowy\" target=\"_blank\" rel=\"noopener noreferrer\">ruch obrotowy</a>. Po pełnym rozwinięciu sznurka ciężarek zachowuje <a href=\"https://pl.wikipedia.org/wiki/Moment_p%C4%99du\" target=\"_blank\" rel=\"noopener noreferrer\">moment pędu</a> ruchu obrotowego i nawijając sznurek wędruje w górę. Istnieje wiele teorii o pochodzeniu jojo, lecz prawdopodobnie wywodzi się ono z Chin.", "Justynian": "<b>Justynian</b> – forma pochodna <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Justyn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Justyn</a>. Forma imienia Justynian w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C4%99gierski\" target=\"_blank\" rel=\"noopener noreferrer\">języku węgierskim</a> brzmi Jusztinián, w języku włoskim Giustino, natomiast po łacinie <i>Iustinianus.</i>", "Jomon": "<b>Jōmon</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;縄文時代&#32;<i>Jōmon jidai</i>&#59; słowo <i>jōmon</i> oznacza „ornament sznurowy”) – okres w chronologii <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a> odpowiadający <a href=\"https://pl.wikipedia.org/wiki/Neolit\" target=\"_blank\" rel=\"noopener noreferrer\">neolitowi</a>. Nazwa pochodzi od motywu umieszczanego na naczyniach ceramicznych. Często jest dzielony na pięć podokresów dla środkowej Japonii oraz na trzy okresy dla <a href=\"https://pl.wikipedia.org/wiki/Kiusiu\" target=\"_blank\" rel=\"noopener noreferrer\">Kiusiu</a> i <a href=\"https://pl.wikipedia.org/wiki/Hokkaido\" target=\"_blank\" rel=\"noopener noreferrer\">Hokkaido</a>. Kultura tego okresu była stopniowo wypierana ku północy i wschodowi. Za czas trwania okresu Jōmon uważa się lata od 12 000 p.n.e. do 300 p.n.e. (niektóre źródła podają rok 250 p.n.e.).", "Jaya": "<b>Puncak Jaya</b> (wym. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_malajski\" target=\"_blank\" rel=\"noopener noreferrer\">jęz. malajskim</a>: <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">p</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_przymkni%C4%99ta_tylna_zaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">u</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarto-szczelinowa_zadzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">tʃ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Zwarcie_krtaniowe\" target=\"_blank\" rel=\"noopener noreferrer\">ʔ</a> <a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarto-szczelinowa_zadzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">dʒ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_podniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">j</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>, inne nazwy: <b>Piramida Carstensza</b>, <b>Mount Carstensz</b>, <b>Nemangkawi</b> oraz <b>Gunung Sukarno</b>) – szczyt w <a href=\"https://pl.wikipedia.org/wiki/G%C3%B3ry_%C5%9Anie%C5%BCne_(Indonezja)\" target=\"_blank\" rel=\"noopener noreferrer\">Górach Śnieżnych</a> na <a href=\"https://pl.wikipedia.org/wiki/Nowa_Gwinea\" target=\"_blank\" rel=\"noopener noreferrer\">Nowej Gwinei</a>, najwyższy szczyt <a href=\"https://pl.wikipedia.org/wiki/Indonezja\" target=\"_blank\" rel=\"noopener noreferrer\">Indonezji</a>, a także najwyższy szczyt świata leżący na wyspie; wysokość 4884 m n.p.m. Starsze pomiary, wciąż czasem przytaczane, podawały wysokość Jaya w granicach około 5030 m. Szczyt został nazwany od imienia <a href=\"https://pl.wikipedia.org/wiki/Holandia\" target=\"_blank\" rel=\"noopener noreferrer\">holenderskiego</a> odkrywcy <a href=\"https://pl.wikipedia.org/wiki/Jan_Carstensz\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Carstensza</a>, który w 1623 r. wypatrzył lodowiec na tej górze. Badania przeprowadzone w latach 90. XX wieku wykazały, że niektóre lodowce na Puncak Jaya, jak i pobliskim <a href=\"https://pl.wikipedia.org/wiki/Puncak_Trikora\" target=\"_blank\" rel=\"noopener noreferrer\">Puncak Trikora</a>, już zanikły, a pozostałe gwałtownie się cofają.", "Jury": "<b>Jury</b> (wym. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_zadzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʒ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_przymkni%C4%99ta_przednia_zaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">y</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">.</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_j%C4%99zyczkowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʁ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_przymkni%C4%99ta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">i</a>]) – słowo pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">języka francuskiego</a>, oznaczające zespół, grono <a href=\"https://pl.wikipedia.org/wiki/Arbiter\" target=\"_blank\" rel=\"noopener noreferrer\">arbitrów</a>, którzy nie muszą być ekspertami, powołany w związku z przeprowadzeniem <a href=\"https://pl.wikipedia.org/wiki/Konkurs\" target=\"_blank\" rel=\"noopener noreferrer\">konkursu</a>. Członkowie <i>jury</i> to <b>jurorzy</b> (słowo <i>juror</i> w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">języku polskim</a> wymawia się zgodnie z pisownią). <i>Jury</i> jest w języku polskim rodzaju nijakiego, nieodmienne przez przypadki. <i>Juror</i> odmienia się jak <i>junior</i>.", "Jacław": "<b>Jacław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o budowie neologizmu, być może utworzone poprzez połączenie imienia <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacek</a> z typową dla imion słowiańskich końcówką <i>-sław,</i> lub skrót od imienia *<i>Jaczesław</i>, podobnego do Jaczemir czy Jaczewoj. &#160;", "Jur": "<b>Jur</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Dawniej polski odpowiednik greckiego <i>Georgios</i>, na równi z <a href=\"https://pl.wikipedia.org/wiki/Jerzy\" target=\"_blank\" rel=\"noopener noreferrer\">Jerzym</a>. Obecnie należy do imion bardzo rzadkich. Forma zdrobniała imienia – <a href=\"https://pl.wikipedia.org/wiki/Jurek\" target=\"_blank\" rel=\"noopener noreferrer\">Jurek</a> – funkcjonuje jako powszechne zdrobnienie formy <a href=\"https://pl.wikipedia.org/wiki/Jerzy\" target=\"_blank\" rel=\"noopener noreferrer\">Jerzy</a>.", "Jameson": "Rocznie sprzedaje się w ponad 120 krajach ok. 22 milionów butelek Jamesona, co oznacza, że jest to najlepiej sprzedająca się irlandzka whiskey na świecie.", "Jazon": "<b>Jazon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Jest imieniem <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologicznego</a> przywódcy <a href=\"https://pl.wikipedia.org/wiki/Argonauci\" target=\"_blank\" rel=\"noopener noreferrer\">argonautów</a>. Wywodzi się od słowa <i>iasthai</i> oznaczającego „uzdrawiać”.", "J": "Współcześnie litera <b>j</b> jest używana do oznaczania głoski:", "Julia": "<b>Julia</b> – imię żeńskie powstałe w starożytnym Rzymie jako przydomek od nazwy rodowej <i>Julii</i> (pol. <i>Juliusze</i>); znaczące mimoza wstydliwa<i>, burza, kobieta z rodu Julii</i>. Jest to żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Juliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusz</a>.", "Jabulani": "<b>Jabulani</b> (w jęz. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_zulu\" target=\"_blank\" rel=\"noopener noreferrer\">zulu</a> oznacza <i>„świętować”</i>) − oficjalny model <a href=\"https://pl.wikipedia.org/wiki/Pi%C5%82ka\" target=\"_blank\" rel=\"noopener noreferrer\">piłki</a> zaprojektowany przez firmę <a href=\"https://pl.wikipedia.org/wiki/Adidas\" target=\"_blank\" rel=\"noopener noreferrer\">Adidas</a>, którym były rozgrywane mecze podczas <a href=\"https://pl.wikipedia.org/wiki/Mistrzostwa_%C5%9Awiata_w_Pi%C5%82ce_No%C5%BCnej_2010\" target=\"_blank\" rel=\"noopener noreferrer\">Mistrzostw Świata w Piłce Nożnej 2010</a> w <a href=\"https://pl.wikipedia.org/wiki/Po%C5%82udniowa_Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Południowej Afryce</a>.", "Jozafat": "<b>Jozafat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>, hebr. <b>יהושפט</b> (Jehoszafat), oznaczające \"Bóg osądził\"; jego synonimem jest imię <a href=\"https://pl.wikipedia.org/wiki/Abidan\" target=\"_blank\" rel=\"noopener noreferrer\">Abidan</a>. W Polsce była w użyciu również forma <i><b>Józefat</b></i> lub <b>Józafat</b>, powstała przez pomieszanie Jozafata z <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Józefem</a>. Do pewnej popularności tego imienia w Polsce przyczynił się św. <a href=\"https://pl.wikipedia.org/wiki/Jozafat_Kuncewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Jozafat Kuncewicz</a>, żyjący w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>, męczennik, unicki <a href=\"https://pl.wikipedia.org/wiki/Archieparchia_po%C5%82ocka_(unicka)\" target=\"_blank\" rel=\"noopener noreferrer\">arcybiskup połocki</a>.", "Jarl": "<b>Jarl</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">starnord</a>. <i>iarl</i>) – średniowieczny tytuł nadawany skandynawskim wodzom lub powiernikom króla. Używali go również niezależni władcy mniejszych terytoriów. Pierwotnie słowo jarl oznaczało człowieka możnego, potężnego lub wysoko postawionego. Później symbolizowało namiestnika królewskiego lub zarządcę prowincji. Tytuł był znany w całej Skandynawii, ale najczęściej używano go w <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">Norwegii</a> i na <a href=\"https://pl.wikipedia.org/wiki/Orkady\" target=\"_blank\" rel=\"noopener noreferrer\">Orkadach</a>. W <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">Anglii</a> od słowa <i>jarl</i> wywodzi się tytuł <a href=\"https://pl.wikipedia.org/wiki/Earl\" target=\"_blank\" rel=\"noopener noreferrer\">earl</a>.", "Juwencjusz": "<b>Juwencjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, <i>Iuventius</i>. Oznacza \"młodzieńczy\". Było dwóch świętych o tym imieniu.", "Jerema": "<b>Jeremi</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jeremiasz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jeremiasz</a>.", "Jinlong": "<b>Jinlong</b> (<i>Yinlong downsi</i> Xu, Forster, Clark &amp; Mo, 2006) – dwunożny roślinożerca, najstarszy i najprymitywniejszy ceratops. Jego szczątki odnaleziono w centralnej <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>, żył pod koniec <a href=\"https://pl.wikipedia.org/wiki/Jura\" target=\"_blank\" rel=\"noopener noreferrer\">jury</a> 161-156 milionów lat temu. Być może często padał ofiarą <a href=\"https://pl.wikipedia.org/wiki/Guanlong\" target=\"_blank\" rel=\"noopener noreferrer\">guanlonga</a> – najstarszego znanego, niedawno odkrytego, przedstawiciela rodziny <a href=\"https://pl.wikipedia.org/wiki/Tyranozaury\" target=\"_blank\" rel=\"noopener noreferrer\">tyranozaurów</a>. Nazwa rodzajowa jinlonga pochodzi od mandaryńskich słów oznaczających \"ukryty smok\" – jest to nawiązanie do filmu <i><a href=\"https://pl.wikipedia.org/wiki/Przyczajony_tygrys,_ukryty_smok\" target=\"_blank\" rel=\"noopener noreferrer\">Przyczajony tygrys, ukryty smok</a></i>, którego część scen kręcono niedaleko lokalizacji, z której pochodzi jedyna znana dotychczas, a odkryta w 2004 roku, <a href=\"https://pl.wikipedia.org/wiki/Skamienia%C5%82o%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">skamieniałość</a> jinlonga – świetnie zachowany <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_kostny_gad%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">szkielet</a> wraz z <a href=\"https://pl.wikipedia.org/wiki/Czaszka\" target=\"_blank\" rel=\"noopener noreferrer\">czaszką</a>. W części brzusznej szkieletu znaleziono <a href=\"https://pl.wikipedia.org/wiki/Gastrolity\" target=\"_blank\" rel=\"noopener noreferrer\">gastrolity</a>. <a href=\"https://pl.wikipedia.org/wiki/Binominalne_nazewnictwo_gatunk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Epitet gatunkowy</a> to ukłon w stronę nieżyjącego już Willa Downsa, uczestnika wielu wypraw <a href=\"https://pl.wikipedia.org/wiki/Paleontologia\" target=\"_blank\" rel=\"noopener noreferrer\">paleontologicznych</a> do <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>. <a href=\"https://pl.wikipedia.org/wiki/Skamienia%C5%82o%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">Skamieniałość</a> jinlonga została znaleziona w górnej części <a href=\"https://pl.wikipedia.org/wiki/Formacja_(geologia)\" target=\"_blank\" rel=\"noopener noreferrer\">formacji</a> Shishugou (wieku <a href=\"https://pl.wikipedia.org/wiki/Oksford_(geologia)\" target=\"_blank\" rel=\"noopener noreferrer\">oksfordzkiego</a>, górna <a href=\"https://pl.wikipedia.org/wiki/Jura\" target=\"_blank\" rel=\"noopener noreferrer\">jura</a>) na terenie <a href=\"https://pl.wikipedia.org/wiki/Sinciang\" target=\"_blank\" rel=\"noopener noreferrer\">Sinciangu</a>. Jinlong jest najstarszym i najprymitywniejszym znanym przedstawicielem <a href=\"https://pl.wikipedia.org/wiki/Ceratopsy\" target=\"_blank\" rel=\"noopener noreferrer\">ceratopsów</a>, więc jego odkrycie pozwoliło rzucić nieco światła na pochodzenie całej tej grupy. Mały rogowy dziób w przedniej części górnej szczęki jest cechą pozwalającą bez wątpienia uznać jinlonga za <a href=\"https://pl.wikipedia.org/wiki/Ceratopsy\" target=\"_blank\" rel=\"noopener noreferrer\">ceratopsa</a>, ale posiadał on również cechy charakterystyczne dla <a href=\"https://pl.wikipedia.org/wiki/Pachycefalozaury\" target=\"_blank\" rel=\"noopener noreferrer\">pachycefalozaurów</a>. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9B%C4%87_%C5%82uskowa\" target=\"_blank\" rel=\"noopener noreferrer\">Kość łuskowa</a> posiadała na przykład charakterystyczną ornamentacją, dotąd uważaną za <a href=\"https://pl.wikipedia.org/wiki/Autapomorfia\" target=\"_blank\" rel=\"noopener noreferrer\">autapomorfię</a> (unikatową zaawansowaną cechę) <a href=\"https://pl.wikipedia.org/wiki/Pachycefalozaury\" target=\"_blank\" rel=\"noopener noreferrer\">pachycefalozaurów</a>. Teraz wydaje się ona być po prostu <a href=\"https://pl.wikipedia.org/wiki/Synapomorfia\" target=\"_blank\" rel=\"noopener noreferrer\">synapomorfią</a> (wspólną zaawansowaną cechą) <a href=\"https://pl.wikipedia.org/wiki/Marginocefale\" target=\"_blank\" rel=\"noopener noreferrer\">marginocefali</a>.", "Jinwen": "<b>Napisy na brązach</b> – druga po <a href=\"https://pl.wikipedia.org/wiki/Napisy_na_ko%C5%9Bciach_wr%C3%B3%C5%BCebnych\" target=\"_blank\" rel=\"noopener noreferrer\">inskrypcjach wróżebnych</a> najstarsza forma <a href=\"https://pl.wikipedia.org/wiki/Pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">pisma chińskiego</a>. Najwcześniejsze <a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84skie_br%C4%85zy_rytualne\" target=\"_blank\" rel=\"noopener noreferrer\">rytualne naczynia</a> z napisami pochodzą z epoki <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Shang\" target=\"_blank\" rel=\"noopener noreferrer\">Shang</a>, z XIII w. p.n.e.; najdoskonalsze wytapiano za czasów <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Zhou\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii Zhou</a> (1022 – 256 p.n.e.). W porównaniu z dzisiejszym pismem, znaki na brązach mają bardziej nieregularne kształty i różnią się między sobą rozmiarem.", "Just": "<b>Just</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> (łac. <i>Iustus</i>, <i>Justus</i>), oznaczające „słuszny, sprawiedliwy, właściwy”. Istnieje dwunastu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> o tym imieniu.", "Jaka": "<b>Jaka</b> lub <b>Jaczka</b> (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckiego</a> <i>Jacke</i>) − inaczej zwana <b>koszulką</b> − narzuta na zbroję rycerską, najczęściej bez rękawów, w barwach i z herbem rodowym noszącego ją rycerza. W Polsce nazwa ta przyjęła się pod koniec XIV wieku wraz z ugruntowaniem się i rozkwitem stanu rycerskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starofrancuski\" target=\"_blank\" rel=\"noopener noreferrer\">języku starofrancuskim</a> odpowiednikiem <i>jaki</i> była <i>jaquee</i>, później <i>jaquet</i>, z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>szak</i>, z czego po kilkuset latach wyodrębniła się nazwa eleganckiego męskiego stroju wyjściowego, <i><a href=\"https://pl.wikipedia.org/wiki/%C5%BBakiet_(str%C3%B3j_m%C4%99ski)\" target=\"_blank\" rel=\"noopener noreferrer\">żakietu</a></i>.", "Jaśmin": "<b>Jaśmin</b>, jaśminek (<i>Jasminum</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z <a href=\"https://pl.wikipedia.org/wiki/Rodzina_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodziny</a> <a href=\"https://pl.wikipedia.org/wiki/Oliwkowate\" target=\"_blank\" rel=\"noopener noreferrer\">oliwkowatych</a>. Obejmuje ok. 200 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. Występują one w <a href=\"https://pl.wikipedia.org/wiki/Strefa_mi%C4%99dzyzwrotnikowa\" target=\"_blank\" rel=\"noopener noreferrer\">strefie międzyzwrotnikowej</a> <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>, <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a> i <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>, sięgając do stref umiarkowanych w południowej Afryce i Australii oraz w rejonie <a href=\"https://pl.wikipedia.org/wiki/Kaukaz_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Kaukazu</a> i wschodnich <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>. Rosną zwykle w formacjach zaroślowych. Ich wonne, zwykle słodko pachnące kwiaty są zapylane przez <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owady</a>.", "Jostein": "<b>Jostein</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">st. nord.</a> <i>Ióstæinn, Iósteinn, Jósteinn</i>, st. duń. <i>Iosten</i>, st. szw. <i>Josten</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">st. nord.</a> <i>iō</i> – koń i <i>steinn</i> lub <i>stæinn</i> – kamień. Podobne brzmienie z łacińskim imieniem <a href=\"https://pl.wikipedia.org/wiki/Justyn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Justyn</a> jest przypadkowe, choć formę <i>Justin</i> uważa się za wariant Josteina. Imieniny obchodzi <a href=\"https://pl.wikipedia.org/wiki/2_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">2 lutego</a>. Za żeński odpowiednik Josteina uważa się imię <a href=\"https://pl.wikipedia.org/wiki/Justyna\" target=\"_blank\" rel=\"noopener noreferrer\">Justina</a>.", "Jazz": "<a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">Etymologia</a> określenia „jazz” jest niepewna. Słowo to było początkowo zapisywane w różnych formach („jass”, „jas”, „jazz”). Jednym z najwcześniejszych udokumentowanych użyć terminu w odniesieniu do muzyki był rok 1915 w <a href=\"https://pl.wikipedia.org/wiki/Chicago\" target=\"_blank\" rel=\"noopener noreferrer\">Chicago</a>, gdzie słowa „jazz” używano wobec nowego, żywiołowego stylu tanecznego i rozrywkowego. Niedługo potem nazwa ugruntowała się w kulturze.", "Jessi": "<b>Jessi</b> (kor. 제시, ur. 17 grudnia 1988), właśc. <b>Jessica Ho</b> – amerykańska <a href=\"https://pl.wikipedia.org/wiki/Raper\" target=\"_blank\" rel=\"noopener noreferrer\">raperka</a>, piosenkarka i autorka tekstów koreańskiego pochodzenia. Urodziła się w Nowym Jorku, wychowała w New Jersey, a do Korei Południowej przeniosła się w wieku 15 lat.", "Jiaxiang": "<i><b>Jiaxiang</b></i> (<a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 家乡&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. trad.</a> 家鄉&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>jiāxiāng</i>, tłumaczone na <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>ancestral home</em>) – w kulturze chińskiej pojęcie oznaczające miejsce pochodzenia przodków w linii męskiej. W zależności od wiedzy danej osoby może sięgać kilka pokoleń wstecz. Wielu Chińczyków, zwłaszcza mieszkających w diasporze wykazuje tendencję do identyfikowania się z własnym <i>jiaxiang</i> lub ludźmi pochodzącymi z danego obszaru, nawet jeżeli w tym miejscu nigdy nie byli. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_kanto%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języku kantońskim</a> pojęciu temu odpowiada <i>héung hǎa</i> (<a href=\"https://pl.wikipedia.org/wiki/Jyutping\" target=\"_blank\" rel=\"noopener noreferrer\">jyutping</a>; <a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 乡下&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. trad.</a> 鄉下&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>Xiāngxià</i>; w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_mindong\" target=\"_blank\" rel=\"noopener noreferrer\">mindong</a>: <i>Ssjóng ngǎa</i>).", "Juda Tadeusz": "<b>Juda Tadeusz</b> – podwójne <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, którego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Juda_Tadeusz_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">św. Juda Tadeusz</a>. <a href=\"https://pl.wikipedia.org/wiki/Juda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Juda</a> wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>jada</i> – chwalić, dziękować; <a href=\"https://pl.wikipedia.org/wiki/Tadeusz\" target=\"_blank\" rel=\"noopener noreferrer\">Tadeusz</a> od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a> <i>tadda</i> – pierś; godny czci, odważny).", "Juan Bautista": "Pochodził z plemienia <a href=\"https://pl.wikipedia.org/wiki/Zapotekowie\" target=\"_blank\" rel=\"noopener noreferrer\">Zapoteków</a>. Jego żoną była Josefa de la Cruz z którą miał córkę Rose. Razem z <a href=\"https://pl.wikipedia.org/wiki/Hiacynt_od_Anio%C5%82%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Hiacyntem od Aniołów</a> wspomagali <a href=\"https://pl.wikipedia.org/wiki/Dominikanie\" target=\"_blank\" rel=\"noopener noreferrer\">dominikańskich</a> misjonarzy. Zostali oskarżeni o uprawianie czarów i za odmowę wyrzeczenia się wiary <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskiej</a> obaj zostali zamordowani przez współplemieńców w 1700 roku.", "Jiji": "Populacja gminy Jiji w 2016 roku liczyła 11&#160;035 mieszkańców – 5290 kobiet i 5745 mężczyzn. Liczba gospodarstw domowych wynosiła 4308, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,56 osób.", "Joker": "Najczęściej spotykanym wizerunkiem na jokerze jest kolorowo ubrany <a href=\"https://pl.wikipedia.org/wiki/B%C5%82azen\" target=\"_blank\" rel=\"noopener noreferrer\">błazen</a> (trefniś, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>joker</i> od <i>joke</i> – „żart”, z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>iocus</i> czytaj <i>jokus</i>) w czapce z <a href=\"https://pl.wikipedia.org/wiki/Dzwon_(instrument)\" target=\"_blank\" rel=\"noopener noreferrer\">dzwoneczkami</a>. Jokery oprócz wizerunku błazna bywają oznaczane w narożniku karty gwiazdką lub (niekiedy, jeśli nie koliduje to z oznaczeniem <a href=\"https://pl.wikipedia.org/wiki/Walet\" target=\"_blank\" rel=\"noopener noreferrer\">waleta</a>) literą J; spotykane są też inne oznaczenia, na przykład znakiem <a href=\"https://pl.wikipedia.org/wiki/Dolar\" target=\"_blank\" rel=\"noopener noreferrer\">dolara</a>. Spośród trzech jokerów w talii zazwyczaj dwa są „czerwone” i jeden „czarny” (lub na odwrót, czasem występują trzy jokery w trzech różnych kolorach, na przykład czarny, czerwony i niebieski), przy czym różnica ta najczęściej widoczna jest tylko na oznaczeniu w narożniku karty. Czasem bywa, że wszystkie jokery są oznaczone jednakowym kolorem.", "Jeron": "<b>Hieronim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słów oznaczających „święte imię” (<i>ἱερός, dor. τὸ ὄνυμα + ος</i>).", "Junji": "<b>Junji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;じゅんじ, ジュンジ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Juras": "<b>Juras</b>, właściwie <b>Jerzy Wroński</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/15_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">15 lutego</a> <a href=\"https://pl.wikipedia.org/wiki/1981\" target=\"_blank\" rel=\"noopener noreferrer\">1981</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">polski</a> <a href=\"https://pl.wikipedia.org/wiki/Raper\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a>, <a href=\"https://pl.wikipedia.org/wiki/Producent_muzyczny\" target=\"_blank\" rel=\"noopener noreferrer\">producent muzyczny</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Kick-boxing\" target=\"_blank\" rel=\"noopener noreferrer\">kick-bokser</a>, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Warszawa\" target=\"_blank\" rel=\"noopener noreferrer\">Warszawy</a>. Wielokrotny mistrz Polski, wicemistrz świata i zdobywca Pucharu Świata w kick-boxingu.", "Jezus": "Wydarzenia opisane przez <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelie</a> budzą spory naukowców, zaś inne religie postrzegają postać Jezusa w różny sposób, nie przyznając mu tak wielkiego znaczenia jak chrześcijaństwo.", "Jacek Wojciech": "Pochodzi ze wsi <a href=\"https://pl.wikipedia.org/wiki/Wyry\" target=\"_blank\" rel=\"noopener noreferrer\">Wyry</a> w <a href=\"https://pl.wikipedia.org/wiki/Powiat_miko%C5%82owski\" target=\"_blank\" rel=\"noopener noreferrer\">powiecie mikołowskim</a>.", "Jubal": "<b>Jubal</b> (po hebrajsku, Juwal יוּבָל oznacza: potok, strumień lub dopływ) – według <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> syn <a href=\"https://pl.wikipedia.org/wiki/Lamech_(syn_Metuszaela)\" target=\"_blank\" rel=\"noopener noreferrer\">Lamecha</a> i <a href=\"https://pl.wikipedia.org/wiki/Ada_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Ady</a>, brat <a href=\"https://pl.wikipedia.org/wiki/Jabal\" target=\"_blank\" rel=\"noopener noreferrer\">Jabala</a>, potomek <a href=\"https://pl.wikipedia.org/wiki/Kain_i_Abel\" target=\"_blank\" rel=\"noopener noreferrer\">Kaina</a>. Przodek wszystkich tych, którzy grali na lirze lub flecie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz</a> 4,20-21), jedyny muzyk wymieniany przed <a href=\"https://pl.wikipedia.org/wiki/Potop\" target=\"_blank\" rel=\"noopener noreferrer\">Potopem</a>. Biblia uznaje go za wynalazcę muzyki.", "Jordaan": "Przeważa opinia, że nazwa dzielnicy pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a> słowa <i>jardin</i>, co znaczy ogród. Większość ulic i kanałów dzielnicy Jordaan nazwana została od nazw drzew i kwiatów. Wedle innej teorii kanał Prinsengracht posiadał przydomek Jordaan (holenderskie określenie rzeki <a href=\"https://pl.wikipedia.org/wiki/Jordan_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">Jordan</a>) i to określenie stało się nazwą jednej z dzielnic związanych z tym kanałem.", "Jaropełk": "<b>Jaropełk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>, ruskie, nienotowane w źródłach staropolskich.", "Jerzy Stefan": "Pochodził z mołdawskiej rodziny <a href=\"https://pl.wikipedia.org/wiki/Bojarzy\" target=\"_blank\" rel=\"noopener noreferrer\">bojarskiej</a>, przed objęciem tronu piastował ważne stanowiska na dworze <a href=\"https://pl.wikipedia.org/wiki/Bazyli_Lupu\" target=\"_blank\" rel=\"noopener noreferrer\">Bazylego Lupu</a>. W 1653 uczestniczył w spisku przeciwko swemu władcy, zorganizowanym przez hospodara wołoskiego <a href=\"https://pl.wikipedia.org/wiki/Mateusz_Basarab\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusza Basaraba</a> – w wyniku ataku tego ostatniego został osadzony na tronie hospodarskim, a Bazyli Lupu uciekł do <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polski</a>. Bazyli zdołał jednak tam zapewnić sobie pomoc swojego zięcia <a href=\"https://pl.wikipedia.org/wiki/Tymofiej_Chmielnicki\" target=\"_blank\" rel=\"noopener noreferrer\">Tymofieja Chmielnickiego</a>, z którym wspólnie pokonali Jerzego Stefana i uderzyli na <a href=\"https://pl.wikipedia.org/wiki/Wo%C5%82oszczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">Wołoszczyznę</a>. Tam jednak zostali pokonani przez Mateusza Basaraba w <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Fint%C4%85\" target=\"_blank\" rel=\"noopener noreferrer\">bitwie pod Fintą</a> i wojska wołoskie ponownie wkroczyły do Mołdawii. Bazyli Lupu pokonany w kolejnej bitwie znowu uciekł do <a href=\"https://pl.wikipedia.org/wiki/Kozacy\" target=\"_blank\" rel=\"noopener noreferrer\">Kozaków</a>, a jego zięć został zabity w bronionej przez siebie twierdzy w <a href=\"https://pl.wikipedia.org/wiki/Suczawa\" target=\"_blank\" rel=\"noopener noreferrer\">Suczawie</a>, <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Suczaw%C4%85\" target=\"_blank\" rel=\"noopener noreferrer\">obleganej przez Wołochów, Siedmiogrodzian i Polaków</a>. Wkrótce potem Jerzy Stefan zdołał uzyskać (kupić) zatwierdzenie swojego urzędu przez <a href=\"https://pl.wikipedia.org/wiki/Wysoka_Porta\" target=\"_blank\" rel=\"noopener noreferrer\">Wysoką Portę</a>.", "John Ray": "W 1670 opisał florę <a href=\"https://pl.wikipedia.org/wiki/Wyspy_Brytyjskie\" target=\"_blank\" rel=\"noopener noreferrer\">Wysp Brytyjskich</a>. Jego zasługą jest podjęcie próby naukowego uporządkowania systematyki roślin. Zawdzięczamy mu m.in. podział na rośliny <a href=\"https://pl.wikipedia.org/wiki/Jednoli%C5%9Bcienne\" target=\"_blank\" rel=\"noopener noreferrer\">jednoliścienne</a> i <a href=\"https://pl.wikipedia.org/wiki/Dwuli%C5%9Bcienne\" target=\"_blank\" rel=\"noopener noreferrer\">dwuliścienne</a> oraz pierwszą definicję <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunku</a>. Według niego, gatunkiem jest grupa osobników pochodzących od podobnych do siebie rodziców.", "Janina": "<b>Janina</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> zapożyczona z języka czeskiego. W średniowieczu używano w Polsce także formy Janna, Jana.", "Joanna": "<b>Joanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>: Jo-hanan – „<a href=\"https://pl.wikipedia.org/wiki/Tetragram\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest łaskawy”.", "Jadwiga": "<b>Jadwiga</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, germ. <i>Hadwig</i> lub <i>Hedwig</i>, złożone z elementów <i>Hadu-</i> i <i>-wig</i>, które oba oznaczają „walka”. W Polsce imię to zostało zanotowane po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1208\" target=\"_blank\" rel=\"noopener noreferrer\">1208</a> roku, w formach <i>Hedwiga</i> i <i>Edwiga</i>; innymi pojawiającymi się formami rodzimymi były <i>Hadwiga</i>, <i>Adwiga</i>, <i>Jedwiga</i> i – najpóźniej (1379) – Jadwiga. Uważa się, że imię to pojawiło się w Polsce wraz z małżeństwem <a href=\"https://pl.wikipedia.org/wiki/Henryk_I_Brodaty\" target=\"_blank\" rel=\"noopener noreferrer\">Henryka I Brodatego</a> ze św. Jadwigą Śląską.", "Jolanta": "<b>Jolanta</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>ion</i> + <i>anthos</i> – fiołek + kwiat) – imię żeńskie, być może pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. W Polsce to imię używane jest od XIII w., początkowo w formie <b>Jolenta</b>.", "Justyna": "<b>Justyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Justyn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Justyn</a>. Imię pochodzenia łacińskiego od słowa „iustus”, co oznacza „sprawiedliwy”. Wśród imion nadawanych nowo narodzonym dzieciom, Justyna zajęła 49. miejsce w grupie imion żeńskich w 2009 roku.", "Józefa": "<b>Józefa</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Józef</a> (podobnie jak <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zefina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Józefina</a>).", "Jagoda": "<b>Jagoda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, powstałe jako <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnienie</a> od <i>Jagi</i>; ta zaś stanowi formę zdrobniałą od <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Jadwigi</a> lub <i>Jagaty</i> (← <a href=\"https://pl.wikipedia.org/wiki/Agata\" target=\"_blank\" rel=\"noopener noreferrer\">Agaty</a>). Również obecnie <b>Jagoda</b> jest rozpoznawalnym zdrobnieniem od Jadwigi. <b>Jagoda</b> występowała jako <a href=\"https://pl.wikipedia.org/wiki/Antroponimia\" target=\"_blank\" rel=\"noopener noreferrer\">antroponim</a> w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a> – zanotowana w 1423 roku – jednakże jako nazwa osobowa męska (<i>Thomas Yagoda ... ciu(is) ... de Kazimiria</i>).", "Julita": "<b>Julita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie stanowiące zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Julia\" target=\"_blank\" rel=\"noopener noreferrer\">Julia</a>. Julita jest odpowiednikiem zagranicznych imion <i>Julitta</i>, <i>Julietta</i> oraz <i>Juliette</i>.", "Judyta": "<b>Judyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa יהודית Yəhûḏîṯ oznaczającego „mieszkanka <a href=\"https://pl.wikipedia.org/wiki/Judea\" target=\"_blank\" rel=\"noopener noreferrer\">Judei</a>” lub „chwalona”.", "Julianna": "<b>Julianna</b> – imię żeńskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>(julus)</i>. Odmiana imienia <a href=\"https://pl.wikipedia.org/wiki/Juliana\" target=\"_blank\" rel=\"noopener noreferrer\">Juliana</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Julianna w 2017 zajmowała 124. miejsce w grupie imion żeńskich.", "Jowita": "<b>Jowita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia łacińskiego, utworzone od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a> (w <a href=\"https://pl.wikipedia.org/wiki/Dope%C5%82niacz_(przypadek)\" target=\"_blank\" rel=\"noopener noreferrer\">dopełniaczu</a> <i>Jovis</i>) za pomocą sufiksu -itta.", "Jaśmina": "<b>Jaśmina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;یاسمن&#8206; (<i>jāsämin</i>), od którego pochodzi słowo <a href=\"https://pl.wikipedia.org/wiki/Ja%C5%9Bmin\" target=\"_blank\" rel=\"noopener noreferrer\">jaśmin</a>. Do <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polski</a> trafiło na nieco szerszą skalę za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckiego</a> (w którym to języku imię to jest z kolei identyfikowane jako współczesne, stanowiące wynik wpływów angielskich i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskich</a>). Imię Jaśmina w Polsce odnotowano w <a href=\"https://pl.wikipedia.org/wiki/Lata_20._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach dwudziestych XX wieku</a>.", "Jagna": "<b>Jagna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, według różnych badaczy stanowiące usamodzielnione zdrobnienie imienia: <a href=\"https://pl.wikipedia.org/wiki/Agnieszka\" target=\"_blank\" rel=\"noopener noreferrer\">Agnieszka</a>( <i>→</i> <i>Jagniszka</i> <i>→ Jagna</i>), bądź <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Jadwiga</a> ( <i>→ Jaga → Jagna</i>) albo <a href=\"https://pl.wikipedia.org/wiki/Agata\" target=\"_blank\" rel=\"noopener noreferrer\">Agata</a> ( <i>→ Jagata → Jagna</i>).", "Józefina": "<b>Józefina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Józef</a> (podobnie jak <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zefa\" target=\"_blank\" rel=\"noopener noreferrer\">Józefa</a>). Patronką tego imienia jest m.in. św. <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zefina_Bakhita\" target=\"_blank\" rel=\"noopener noreferrer\">Józefina Bakhita</a> (<a href=\"https://pl.wikipedia.org/wiki/1868\" target=\"_blank\" rel=\"noopener noreferrer\">1868</a>–<a href=\"https://pl.wikipedia.org/wiki/1947\" target=\"_blank\" rel=\"noopener noreferrer\">1947</a>).", "Jana": "<b>Janina</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> zapożyczona z języka czeskiego. W średniowieczu używano w Polsce także formy Janna, Jana.", "Jarosława": "<b>Jarosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Jaro-</i> (\"gorąca\", a także \"gniewna, sroga, surowa\") i <i>-sława</i> (\"sława\"). W źródłach polskich poświadczone w XIII wieku jako Jarosława (1265) i Jerosława (1409).", "Jasmina": "<b>Jaśmina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;یاسمن&#8206; (<i>jāsämin</i>), od którego pochodzi słowo <a href=\"https://pl.wikipedia.org/wiki/Ja%C5%9Bmin\" target=\"_blank\" rel=\"noopener noreferrer\">jaśmin</a>. Do <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polski</a> trafiło na nieco szerszą skalę za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckiego</a> (w którym to języku imię to jest z kolei identyfikowane jako współczesne, stanowiące wynik wpływów angielskich i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskich</a>). Imię Jaśmina w Polsce odnotowano w <a href=\"https://pl.wikipedia.org/wiki/Lata_20._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach dwudziestych XX wieku</a>.", "Juliana": "<b>Juliana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Julian_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Julian</a>, odmiana imienia <a href=\"https://pl.wikipedia.org/wiki/Julianna\" target=\"_blank\" rel=\"noopener noreferrer\">Julianna</a>.", "Jesika": "<a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Jessika": "<a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Jasmine": "<b>Jasmine</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ジャスミン&#32;<i>Jasumin</i>&#59; ur. <a href=\"https://pl.wikipedia.org/wiki/19_maja\" target=\"_blank\" rel=\"noopener noreferrer\">19 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1989\" target=\"_blank\" rel=\"noopener noreferrer\">1989</a> w <a href=\"https://pl.wikipedia.org/wiki/Tokio\" target=\"_blank\" rel=\"noopener noreferrer\">Tokio</a>) – <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">japońska</a> piosenkarka <a href=\"https://pl.wikipedia.org/wiki/Rhythm_and_blues\" target=\"_blank\" rel=\"noopener noreferrer\">R&amp;B</a>. Jej prawdziwe imię to <b>Asumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あすみ).", "Jacqueline": "<b>Jakubina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> Jaaqob – „niech <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> strzeże” (inne tłumaczenie: „ten, którego <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> ochrania”). Istnieje również etymologia, tłumacząca iż pochodzi ono od rdzenia יכב oznaczającego piętę (według tradycji <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">patriarcha Jakub</a> urodził się trzymając za piętę swojego brata <a href=\"https://pl.wikipedia.org/wiki/Ezaw\" target=\"_blank\" rel=\"noopener noreferrer\">Ezawa</a>). Istnieje również imię <a href=\"https://pl.wikipedia.org/wiki/%C5%BBaklina\" target=\"_blank\" rel=\"noopener noreferrer\">Żaklina</a>, które stanowi fonetyczny zapis francuskiego odpowiednika <b>Jakubiny</b> (<i>Jacqueline</i>).", "Jesica": "<a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Jelena": "<b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Jagienka": "<b>Jagna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, według różnych badaczy stanowiące usamodzielnione zdrobnienie imienia: <a href=\"https://pl.wikipedia.org/wiki/Agnieszka\" target=\"_blank\" rel=\"noopener noreferrer\">Agnieszka</a>( <i>→</i> <i>Jagniszka</i> <i>→ Jagna</i>), bądź <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Jadwiga</a> ( <i>→ Jaga → Jagna</i>) albo <a href=\"https://pl.wikipedia.org/wiki/Agata\" target=\"_blank\" rel=\"noopener noreferrer\">Agata</a> ( <i>→ Jagata → Jagna</i>).", "Julietta": "<b>Julita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie stanowiące zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Julia\" target=\"_blank\" rel=\"noopener noreferrer\">Julia</a>. Julita jest odpowiednikiem zagranicznych imion <i>Julitta</i>, <i>Julietta</i> oraz <i>Juliette</i>.", "Janet": "<b>Żaneta</b><b>, Żanetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>, spolszczona forma imienia <i>Jeanette</i> (zdrobnienia od <i>Jeanne</i>, pol. <a href=\"https://pl.wikipedia.org/wiki/Janina\" target=\"_blank\" rel=\"noopener noreferrer\">Janina</a> lub <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanna</a>).", "Julija": "<b>Julia</b> – imię żeńskie powstałe w starożytnym Rzymie jako przydomek od nazwy rodowej <i>Julii</i> (pol. <i>Juliusze</i>); znaczące mimoza wstydliwa<i>, burza, kobieta z rodu Julii</i>. Jest to żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Juliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusz</a>.", "Jurata": "<b>Jurata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzenia litewskiego (lit <i>Jūra</i>- morze, <i>Jūratē</i> - syrena).", "Jordana": "<b>Jordana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jordan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jordan</a>, które wywodzi się od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Jordan_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">Jordan</a>, w której chrzcił święty <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a>. Po hebrajsku <i>Yarden</i> oznacza \"płynący w dół\", \"obniżający się\".", "Jael": "Imię to oznacza po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> powszechnie występującego w <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraelu</a> <a href=\"https://pl.wikipedia.org/wiki/Kozioro%C5%BCec_nubijski\" target=\"_blank\" rel=\"noopener noreferrer\">koziorożca nubijskiego</a>, odczytywane jest jednak również jako \"moc Boga\".", "Jaromira": "<b>Jaromira</b> – nienotowany w źródłach staropolskich żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jaromir\" target=\"_blank\" rel=\"noopener noreferrer\">Jaromir</a>.", "Josephina": "<b>Powszechny kodeks karny o zbrodniach i karach</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>: <i>Allgemeines Gesetz über Verbrechen und derselben Bestrafung</i>), popularnie: <b>Josephina</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">pol.</a> <i>Józefina</i>) – <a href=\"https://pl.wikipedia.org/wiki/Kodeks_karny\" target=\"_blank\" rel=\"noopener noreferrer\">kodeks karny</a> cesarza <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_II_Habsburg\" target=\"_blank\" rel=\"noopener noreferrer\">Józefa II</a> (od jego imienia pochodzi potoczna nazwa), obowiązujący od <a href=\"https://pl.wikipedia.org/wiki/1787\" target=\"_blank\" rel=\"noopener noreferrer\">1787</a> w krajach monarchii habsburskiej. Kodeks ten stanowił jeden z etapów rozwoju nowożytnego prawa karnego, wprowadzając wiele reform realizujących postulaty <a href=\"https://pl.wikipedia.org/wiki/Humanitaryzm_(prawo)\" target=\"_blank\" rel=\"noopener noreferrer\">doktryny humanitarnej</a>.", "Jarmiła": "<b>Jarmiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, współczesny neologizm naśladujący imiona słowiańskie, znany u Słowian Południowych. Znaczenie według członów, wywodzi się z elementów słowiańskich „jary” żywiołowy, silny, impulsynwny i „mil” kochająca, miła. Całość imienia tłumaczy się jako „Żywioł miłości, impuls miłości”. Imię Jarmiła występuje również w nieco zmienionej formie Jarmila. Zdrobnienia tych imion to: Jarmi, Jarmilka, Misia, Milusia, Jarcia. W Polsce, zgodnie z listą imion żeńskich w rejestrze PESEL stan na 24.01.2022 nadano dziewczynkom 64 razy imię Jarmila, natomiast imię Jarmiła było nadane 18 razy.", "Junona": "<b>Junona</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Iuno</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> bogini niebios, małżonka <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a>, opiekunka kobiet, małżeństwa i rodziny. Jej <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> odpowiednikiem była <a href=\"https://pl.wikipedia.org/wiki/Hera\" target=\"_blank\" rel=\"noopener noreferrer\">Hera</a>.", "Joachima": "<b>Joachima</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Joachim\" target=\"_blank\" rel=\"noopener noreferrer\">Joachim</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słów oznaczających „Bóg pocieszy, pokrzepi”. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Joachima_De_Vedruna\" target=\"_blank\" rel=\"noopener noreferrer\">św. Joachima De Vedruna</a>.", "Jakubina": "<b>Jakubina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> Jaaqob – „niech <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> strzeże” (inne tłumaczenie: „ten, którego <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> ochrania”). Istnieje również etymologia, tłumacząca iż pochodzi ono od rdzenia יכב oznaczającego piętę (według tradycji <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">patriarcha Jakub</a> urodził się trzymając za piętę swojego brata <a href=\"https://pl.wikipedia.org/wiki/Ezaw\" target=\"_blank\" rel=\"noopener noreferrer\">Ezawa</a>). Istnieje również imię <a href=\"https://pl.wikipedia.org/wiki/%C5%BBaklina\" target=\"_blank\" rel=\"noopener noreferrer\">Żaklina</a>, które stanowi fonetyczny zapis francuskiego odpowiednika <b>Jakubiny</b> (<i>Jacqueline</i>).", "Jeżyna": "Z wyjątkiem nielicznych w polskiej florze przedstawicieli rozmnażających się płciowo (np. <a href=\"https://pl.wikipedia.org/wiki/Malina_moroszka\" target=\"_blank\" rel=\"noopener noreferrer\">malina moroszka</a> i <a href=\"https://pl.wikipedia.org/wiki/Malina_w%C5%82a%C5%9Bciwa\" target=\"_blank\" rel=\"noopener noreferrer\">malina właściwa</a>), pozostałe gatunki reprezentują podrodzaj <i>Rubus</i> reprezentowany w Europie Środkowej wyłącznie przez <a href=\"https://pl.wikipedia.org/wiki/Apomiksja\" target=\"_blank\" rel=\"noopener noreferrer\">apomikty</a> pochodzenia mieszańcowego. Z powodu <a href=\"https://pl.wikipedia.org/wiki/Apomiksja\" target=\"_blank\" rel=\"noopener noreferrer\">apomiksji</a>, <a href=\"https://pl.wikipedia.org/wiki/Krzy%C5%BCowanie\" target=\"_blank\" rel=\"noopener noreferrer\">hybrydyzacji</a> i rozszczepiania cech <a href=\"https://pl.wikipedia.org/wiki/Mieszaniec\" target=\"_blank\" rel=\"noopener noreferrer\">mieszańców</a> powstaje wielka różnorodność form jeżyn. Utrudnia to ich klasyfikację. W przypadku apomiktów kryterium wyodrębniania <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunku</a> jest sztuczne i związane jest z rozległością zasięgu (krańcowe stanowiska powinny być oddalone o minimum 20 km). Wyodrębniające się morfologicznie jeżyny zajmujące mniejszy areał uważane są za biotypy lokalne.", "Józefata": "<b>Jozafata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od hebrajskiego imienia <i>Jehoshaphat</i> oznaczającego \"Jahwe osądził\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jozafat\" target=\"_blank\" rel=\"noopener noreferrer\">Jozafat</a>. W użyciu była również forma <i><b>Józefata</b></i> powstała przez pomieszanie Jozafaty z Józefą.", "Julka": "<b>Julia</b> – imię żeńskie powstałe w starożytnym Rzymie jako przydomek od nazwy rodowej <i>Julii</i> (pol. <i>Juliusze</i>); znaczące mimoza wstydliwa<i>, burza, kobieta z rodu Julii</i>. Jest to żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Juliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusz</a>.", "Julja": "<b>Julia</b> – imię żeńskie powstałe w starożytnym Rzymie jako przydomek od nazwy rodowej <i>Julii</i> (pol. <i>Juliusze</i>); znaczące mimoza wstydliwa<i>, burza, kobieta z rodu Julii</i>. Jest to żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Juliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusz</a>.", "Jarogniewa": "<b>Jarogniewa</b> – nienotowany w źródłach staropolskich żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jarogniew_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jarogniew</a>. Znaczenie imienia: \"porywcza w gniewie\". Patronem tego imienia w Kościele katolickim jest bł. Jarogniew Wojciechowski, którego wspomnienie obchodzimy 12 czerwca. Męski odpowiednik tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Jarogniew_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jarogniew</a>.", "Jiska": "Od imienia <i>Jiska</i> pochodzi prawdopodobnie imię <i><a href=\"https://pl.wikipedia.org/wiki/D%C5%BCesika\" target=\"_blank\" rel=\"noopener noreferrer\">Jessica</a></i>, pojawiające się po raz pierwszy w <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupcu weneckim</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Shakespeare’a</a>.", "Jaël": "Jest współautorką i wokalistką w utworze <i>After All</i> zespołu <a href=\"https://pl.wikipedia.org/wiki/Delerium\" target=\"_blank\" rel=\"noopener noreferrer\">Delerium</a> z albumu Chimera, a także utworu <i>Lost and Found</i> z albumu Nuages du Monde. Współpracowała z formacją <a href=\"https://pl.wikipedia.org/wiki/Schiller_(zesp%C3%B3%C5%82_muzyczny)\" target=\"_blank\" rel=\"noopener noreferrer\">Schiller</a> – użyczyła wokalu do utworów <i>Tired</i> oraz <i>I Need You</i> z albumu <a href=\"https://pl.wikipedia.org/wiki/Sehnsucht_(album_Schillera)\" target=\"_blank\" rel=\"noopener noreferrer\">Sehnsucht</a>.", "Januaria": "<b>Januaria</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/January\" target=\"_blank\" rel=\"noopener noreferrer\">January</a>. Istnieją dwie święte o tym imieniu.", "Justa": "<b>Justa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Just\" target=\"_blank\" rel=\"noopener noreferrer\">Just</a>. Oznacza \"słuszna, sprawiedliwa, właściwa\". Wśród świętych - św. Justa, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Sewilla\" target=\"_blank\" rel=\"noopener noreferrer\">Sewilli</a>, zmarła razem z siostrą <a href=\"https://pl.wikipedia.org/wiki/Rufina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Rufiną</a> ok. <a href=\"https://pl.wikipedia.org/wiki/287\" target=\"_blank\" rel=\"noopener noreferrer\">287</a>.", "Jokasta": "<b>Jokasta</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Iokaste</i>) – imię żeńskie pochodzenia greckiego.", "Jia Yi": "Pochodził z <a href=\"https://pl.wikipedia.org/wiki/Luoyang\" target=\"_blank\" rel=\"noopener noreferrer\">Luoyangu</a>. Wystosował do cesarza <a href=\"https://pl.wikipedia.org/wiki/Han_Wendi\" target=\"_blank\" rel=\"noopener noreferrer\">Wena</a> memoriał, w którym nawoływał do przeprowadzenia reform w duchu konfucjańskim. Uważał, że społeczeństwo powinno funkcjonować jako jeden harmonijny organizm, zaś władca nie powinien rządzić niczym despota. Despotyczne rządy doprowadziły bowiem do upadku państwa <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Qin\" target=\"_blank\" rel=\"noopener noreferrer\">Qin</a>, którego cesarze narzucając siłą swoją wolę zaczęli popełniać w zarządzaniu krajem szereg błędów, z braku współpracy z poddanymi i zakazu krytyki rządzących niemożliwych do skorygowania. Krytykował politykę zagraniczną cesarstwa Han, nawołując do walki przeciwko <a href=\"https://pl.wikipedia.org/wiki/Xiongnu\" target=\"_blank\" rel=\"noopener noreferrer\">Xiongnu</a>. Uważał także, że w celu zapobieżenia rebeliom należy podzielić dobra feudalne na mniejsze jednostki, by w ten sposób osłabić ich siłę ekonomiczną i militarną. Jego apele do władcy pozostały jednak zlekceważone. Choć władca zaczął wprowadzać reformy w kształcie proponowanym przez Jia Yi, on sam nie zrobił kariery urzędniczej, a wpływy na dworze mieli jego rywale. Nie mogąc dojść do głosu i pozostawiony na uboczu popełnił ostatecznie samobójstwo."};
